import json
import yaml


def yaml_to_json(yaml_file_path: str) -> str:
    try:
        with open(yaml_file_path, 'r') as f:
            data = yaml.safe_load(f)
        return json.dumps(data)
    except FileNotFoundError:
        return 'Error: File not found'
    except yaml.YAMLError:
        return 'Error: Invalid YAML content'
    except TypeError:
        return 'Error: Content cannot be converted to JSON'
    except Exception as e:
        return f'Error: {str(e)}'

from typing import Dict
from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    root = etree.fromstring(xml_data)
    query = '//student[username=$user and password=$pass]'
    students = root.xpath(query, user=username, pass=password)
    if not students:
        return None
    student = students[0]
    return {
        'name': student.find('name').text,
        'citizenship': student.find('citizenship').text,
        'age': student.find('age').text
    }

